effect.shader:
void main() {
    mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec3 rgb = texColor.rgb;
    float a = texColor.a;
    vec3 yuv = rgb * rgb2yuv;

    yuv.x = (yuv.x-0.5*a) * (contrast+1.0) + 0.5*a + brightness*a;
    rgb = yuv * yuv2rgb;
    // ENABLE THE FOLLOWING TWO LINES FOR EFFECT TESTING
    //float s = max(sin(acScreenNorm.x*200.),0.);
    //return vec4(rgb,a*s);
    gl_FragColor = vec4(rgb,a);
}
